mapper.select:
SELECT * FROM post_processing_print
WHERE cloth_paper_type_id = #{clothPaperTypeId}
ORDER BY product_name, product_model_number

SELECT COUNT(*) > 0
FROM products p
INNER JOIN specifications s ON p.id = s.project_id
WHERE s.color = #{color}
AND s.color IS NOT NULL
AND s.color != ''

    AND p.name = #{productName}


    AND p.model_number = #{productModelNumber}

SELECT DISTINCT unnest(notice_ids)
FROM post_processing_print
WHERE notice_ids IS NOT NULL
AND array_length(notice_ids, 1) > 0
AND compatibility_status IN ('V', '▷')

    AND cloth_paper_type_id = #{clothPaperTypeId}


    AND product_model_number = #{productModelNumber}


    AND product_name = #{productName}
